#nullable enable // autogenerated

using PVZEngine;

namespace MVZ2Logic.Unlocks
{
    public static class LogicUnlockNames
    {
        public const string blueprintSlot1 = "blueprint_slot.1";
        public const string blueprintSlot2 = "blueprint_slot.2";
        public const string blueprintSlot3 = "blueprint_slot.3";
        public const string blueprintSlot4 = "blueprint_slot.4";

        public const string starshardSlot1 = "starshard_slot.1";
        public const string starshardSlot2 = "starshard_slot.2";

        public const string artifactSlot1 = "artifact_slot.1";
        public const string artifactSlot2 = "artifact_slot.2";
        public static string GetLevelClearUnlock(string stageID)
        {
            return $"level.{stageID}";
        }
    }
    public static class LogicUnlockID
    {
        public static readonly NamespaceID blueprintSlot1 = Get(LogicUnlockNames.blueprintSlot1);
        private static NamespaceID Get(string name)
        {
            return new NamespaceID(Global.BuiltinNamespace, name);
        }
        public static NamespaceID GetLevelClearUnlock(NamespaceID stageID)
        {
            return new NamespaceID(stageID.SpaceName, LogicUnlockNames.GetLevelClearUnlock(stageID.Path));
        }
    }
}
